-- ===========================================================
--  Decoding Customer Value: SQL-Driven Retention Strategy
--  D2C Fashion Brand | FINAL VERSION
--  CVS = 40% Spend + 40% Previous Purchases + 20% Frequency
--  Loyalty: Def B (strict) + Def C (preferred, tenure-based)
--  Compatible: MySQL 8+ / PostgreSQL 13+
-- ===========================================================

DROP TABLE IF EXISTS customers;

CREATE TABLE customers (
    customer_id            INT           PRIMARY KEY,
    purchase_amount_usd    INT           NOT NULL,
    previous_purchases     INT           NOT NULL,
    frequency_score        INT           NOT NULL,
    loyal_def_b            TINYINT       NOT NULL,
    loyal_def_c            TINYINT       NOT NULL,
    promo_dependency_score TINYINT       NOT NULL,
    age_band               VARCHAR(10)   NOT NULL,
    us_region              VARCHAR(20)   NOT NULL,
    category               VARCHAR(20)   NOT NULL,
    season                 VARCHAR(10)   NOT NULL,
    payment_category       VARCHAR(20)   NOT NULL,
    satisfaction_flag      TINYINT       NOT NULL,
    value_tier             VARCHAR(15)   NOT NULL,
    customer_value_score   DECIMAL(6,4)  NOT NULL,
    gender                 VARCHAR(10)   NOT NULL,
    location               VARCHAR(50)   NOT NULL,
    item_purchased         VARCHAR(50)   NOT NULL,
    color                  VARCHAR(30)   NOT NULL,
    age                    INT           NOT NULL
);









































-- ===========================================================
-- Q1 — LOYAL vs DISCOUNT CUSTOMERS
-- ===========================================================

-- Q1a: Core comparison
SELECT
    CASE WHEN loyal_def_c = 1 THEN 'Loyal (Def C — Preferred)'
         WHEN loyal_def_b = 1 THEN 'Loyal (Def B — Strict)'
         ELSE 'Non-Loyal' END                            AS loyalty_segment,
    COUNT(*)                                             AS customer_count,
    ROUND(AVG(purchase_amount_usd), 2)                   AS avg_spend,
    ROUND(AVG(previous_purchases), 2)                    AS avg_tenure,
    ROUND(AVG(customer_value_score), 4)                  AS avg_cvs,
    ROUND(AVG(satisfaction_flag) * 100, 1)               AS satisfaction_pct,
    ROUND(SUM(CASE WHEN promo_dependency_score > 0
              THEN 1.0 ELSE 0 END) * 100.0 / COUNT(*), 1) AS promo_pct
FROM customers
GROUP BY loyalty_segment
ORDER BY avg_cvs DESC;

-- Q1b: Loyal % by value tier (using preferred Def C)
SELECT
    value_tier,
    COUNT(*)                                              AS total_customers,
    SUM(loyal_def_c)                                      AS loyal_count,
    ROUND(SUM(loyal_def_c) * 100.0 / COUNT(*), 1)        AS loyal_pct,
    ROUND(SUM(CASE WHEN promo_dependency_score > 0
              THEN 1.0 ELSE 0 END) * 100.0 / COUNT(*), 1) AS promo_pct
FROM customers
GROUP BY value_tier
ORDER BY CASE value_tier
    WHEN 'Champions' THEN 1 WHEN 'Loyalists' THEN 2
    WHEN 'At Risk' THEN 3 WHEN 'Dormant' THEN 4 END;

-- Q1c: Organic vs Promo revenue contribution
SELECT
    CASE WHEN promo_dependency_score = 0 THEN 'Organic Buyer'
         ELSE 'Promo-Dependent' END                      AS buyer_type,
    COUNT(*)                                             AS customer_count,
    ROUND(AVG(purchase_amount_usd), 2)                   AS avg_spend,
    ROUND(AVG(previous_purchases), 2)                    AS avg_tenure,
    ROUND(AVG(customer_value_score), 4)                  AS avg_cvs,
    SUM(purchase_amount_usd)                             AS total_revenue,
    ROUND(SUM(purchase_amount_usd) * 100.0 /
        (SELECT SUM(purchase_amount_usd) FROM customers), 1) AS revenue_share_pct
FROM customers
GROUP BY promo_dependency_score;

-- ===========================================================
-- Q2 — BEHAVIORAL PATTERNS PREDICTING HIGH VALUE
-- ===========================================================

-- Q2a: Spend x Tenure matrix
SELECT
    CASE WHEN purchase_amount_usd >= 75 THEN 'High Spend (75+)'
         WHEN purchase_amount_usd >= 50 THEN 'Mid Spend (50-74)'
         ELSE 'Low Spend (<50)' END                      AS spend_bucket,
    CASE WHEN previous_purchases >= 34 THEN 'High Tenure (34+)'
         WHEN previous_purchases >= 17 THEN 'Mid Tenure (17-33)'
         ELSE 'Low Tenure (<17)' END                     AS tenure_bucket,
    COUNT(*)                                             AS customer_count,
    ROUND(AVG(customer_value_score), 4)                  AS avg_cvs,
    ROUND(SUM(CASE WHEN value_tier='Champions'
              THEN 1.0 ELSE 0 END) * 100.0 / COUNT(*), 1) AS champion_pct,
    ROUND(SUM(CASE WHEN promo_dependency_score > 0
              THEN 1.0 ELSE 0 END) * 100.0 / COUNT(*), 1) AS promo_pct
FROM customers
GROUP BY spend_bucket, tenure_bucket
ORDER BY avg_cvs DESC;

-- Q2b: Category — entry point vs retention
SELECT
    category,
    COUNT(*)                                             AS customer_count,
    ROUND(AVG(previous_purchases), 2)                    AS avg_tenure,
    ROUND(AVG(purchase_amount_usd), 2)                   AS avg_spend,
    ROUND(AVG(customer_value_score), 4)                  AS avg_cvs,
    ROUND(SUM(CASE WHEN value_tier IN ('Champions','Loyalists')
              THEN 1.0 ELSE 0 END) * 100.0 / COUNT(*), 1) AS high_value_pct,
    ROUND(SUM(CASE WHEN promo_dependency_score > 0
              THEN 1.0 ELSE 0 END) * 100.0 / COUNT(*), 1) AS promo_pct
FROM customers
GROUP BY category
ORDER BY avg_tenure DESC;

-- Q2c: Season vs tenure
SELECT
    season,
    COUNT(*)                                             AS customer_count,
    ROUND(AVG(previous_purchases), 2)                    AS avg_tenure,
    ROUND(AVG(purchase_amount_usd), 2)                   AS avg_spend,
    ROUND(SUM(CASE WHEN previous_purchases <= 10
              THEN 1.0 ELSE 0 END) * 100.0 / COUNT(*), 1) AS new_customer_pct,
    ROUND(SUM(CASE WHEN promo_dependency_score > 0
              THEN 1.0 ELSE 0 END) * 100.0 / COUNT(*), 1) AS promo_pct
FROM customers
GROUP BY season
ORDER BY avg_tenure DESC;

-- ===========================================================
-- Q3 — GEOGRAPHIC OPPORTUNITY
-- ===========================================================

-- Q3a: Region summary
SELECT
    us_region,
    COUNT(*)                                             AS customer_count,
    ROUND(AVG(purchase_amount_usd), 2)                   AS avg_spend,
    ROUND(AVG(customer_value_score), 4)                  AS avg_cvs,
    ROUND(SUM(CASE WHEN promo_dependency_score = 0
              THEN 1.0 ELSE 0 END) * 100.0 / COUNT(*), 1) AS organic_pct,
    ROUND(SUM(loyal_def_c) * 100.0 / COUNT(*), 1)        AS loyal_pct,
    ROUND(SUM(CASE WHEN value_tier='Champions'
              THEN 1.0 ELSE 0 END) * 100.0 / COUNT(*), 1) AS champion_pct
FROM customers
GROUP BY us_region
ORDER BY organic_pct DESC;

-- Q3b: Top 15 organic stronghold states
SELECT
    location                                             AS state,
    COUNT(*)                                             AS total_customers,
    SUM(CASE WHEN promo_dependency_score=0 THEN 1 ELSE 0 END) AS organic_customers,
    ROUND(AVG(CASE WHEN promo_dependency_score=0
              THEN purchase_amount_usd END), 2)          AS organic_avg_spend,
    ROUND(SUM(CASE WHEN value_tier='Champions'
              THEN 1.0 ELSE 0 END) * 100.0 / COUNT(*), 1) AS champion_pct
FROM customers
GROUP BY location
HAVING SUM(CASE WHEN promo_dependency_score=0 THEN 1 ELSE 0 END) >= 10
ORDER BY organic_avg_spend DESC
LIMIT 15;

-- ===========================================================
-- Q4 — PROMOTIONAL STRATEGY RESTRUCTURE
-- ===========================================================

-- Q4a: Promo sunset candidates by tier
SELECT
    value_tier,
    COUNT(*)                                              AS total_in_tier,
    SUM(CASE WHEN promo_dependency_score > 0
             THEN 1 ELSE 0 END)                           AS promo_dependent_count,
    ROUND(SUM(CASE WHEN promo_dependency_score > 0
              THEN 1.0 ELSE 0 END) * 100.0 / COUNT(*), 1) AS promo_pct,
    ROUND(AVG(CASE WHEN promo_dependency_score > 0
              THEN purchase_amount_usd END), 2)           AS promo_avg_spend,
    ROUND(AVG(CASE WHEN promo_dependency_score = 0
              THEN purchase_amount_usd END), 2)           AS organic_avg_spend,
    ROUND(AVG(CASE WHEN promo_dependency_score > 0
              THEN purchase_amount_usd END)
        - AVG(CASE WHEN promo_dependency_score = 0
              THEN purchase_amount_usd END), 2)           AS spend_diff_with_promo
FROM customers
GROUP BY value_tier
ORDER BY CASE value_tier
    WHEN 'Champions' THEN 1 WHEN 'Loyalists' THEN 2
    WHEN 'At Risk' THEN 3 WHEN 'Dormant' THEN 4 END;

-- Q4b: Promo lift by category
SELECT
    category,
    ROUND(AVG(CASE WHEN promo_dependency_score=0
              THEN purchase_amount_usd END), 2)           AS organic_avg_spend,
    ROUND(AVG(CASE WHEN promo_dependency_score > 0
              THEN purchase_amount_usd END), 2)           AS promo_avg_spend,
    ROUND(AVG(CASE WHEN promo_dependency_score > 0
              THEN purchase_amount_usd END)
        - AVG(CASE WHEN promo_dependency_score = 0
              THEN purchase_amount_usd END), 2)           AS promo_spend_lift,
    ROUND(SUM(CASE WHEN promo_dependency_score > 0
              THEN 1.0 ELSE 0 END) * 100.0 / COUNT(*), 1) AS promo_pct
FROM customers
GROUP BY category
ORDER BY promo_spend_lift DESC;

-- Q4c: Sunset priority segments (top 20)
SELECT
    value_tier, age_band, category,
    COUNT(*)                                              AS segment_size,
    ROUND(AVG(previous_purchases), 1)                     AS avg_tenure,
    ROUND(AVG(purchase_amount_usd), 2)                    AS avg_spend,
    ROUND(SUM(CASE WHEN promo_dependency_score > 0
              THEN 1.0 ELSE 0 END) * 100.0 / COUNT(*), 1) AS promo_pct,
    ROUND((AVG(previous_purchases)/50.0 * 0.5)
        + (AVG(purchase_amount_usd)/100.0 * 0.5), 4)      AS sunset_priority_score
FROM customers
WHERE promo_dependency_score > 0
GROUP BY value_tier, age_band, category
HAVING COUNT(*) >= 5
ORDER BY sunset_priority_score DESC
LIMIT 20;

-- ===========================================================
-- Q5 — IDEAL CUSTOMER PROFILE
-- ===========================================================

-- Q5a: Champion segment overview
SELECT
    COUNT(*)                                              AS count,
    ROUND(AVG(purchase_amount_usd), 2)                    AS avg_spend,
    ROUND(AVG(previous_purchases), 2)                     AS avg_tenure,
    ROUND(AVG(frequency_score), 2)                        AS avg_frequency,
    ROUND(AVG(customer_value_score), 4)                   AS avg_cvs,
    ROUND(AVG(satisfaction_flag)*100, 1)                  AS satisfaction_pct,
    ROUND(SUM(CASE WHEN promo_dependency_score=0
              THEN 1.0 ELSE 0 END)*100.0/COUNT(*), 1)     AS organic_pct
FROM customers WHERE value_tier='Champions';

-- Q5b: Age band among Champions
SELECT
    age_band, COUNT(*) AS champion_count,
    ROUND(COUNT(*)*100.0/(SELECT COUNT(*) FROM customers
                          WHERE value_tier='Champions'), 1) AS pct_of_champions
FROM customers WHERE value_tier='Champions'
GROUP BY age_band ORDER BY champion_count DESC;

-- Q5c: Region of organic Champions
SELECT
    us_region, COUNT(*) AS organic_champion_count,
    ROUND(AVG(purchase_amount_usd), 2) AS avg_spend,
    ROUND(AVG(previous_purchases), 2)  AS avg_tenure
FROM customers
WHERE value_tier='Champions' AND promo_dependency_score=0
GROUP BY us_region ORDER BY organic_champion_count DESC;

-- Q5d: Full ICP — single row
SELECT
    (SELECT age_band FROM customers WHERE value_tier='Champions'
     GROUP BY age_band ORDER BY COUNT(*) DESC LIMIT 1)         AS top_age_band,
    (SELECT us_region FROM customers WHERE value_tier='Champions'
     GROUP BY us_region ORDER BY COUNT(*) DESC LIMIT 1)        AS top_region,
    (SELECT category FROM customers WHERE value_tier='Champions'
     GROUP BY category ORDER BY COUNT(*) DESC LIMIT 1)         AS top_category,
    (SELECT season FROM customers WHERE value_tier='Champions'
     GROUP BY season ORDER BY COUNT(*) DESC LIMIT 1)           AS top_season,
    (SELECT payment_category FROM customers WHERE value_tier='Champions'
     GROUP BY payment_category ORDER BY COUNT(*) DESC LIMIT 1) AS top_payment,
    ROUND((SELECT AVG(purchase_amount_usd) FROM customers
           WHERE value_tier='Champions'), 2)                    AS avg_spend,
    ROUND((SELECT AVG(previous_purchases) FROM customers
           WHERE value_tier='Champions'), 1)                    AS avg_tenure,
    ROUND((SELECT AVG(frequency_score) FROM customers
           WHERE value_tier='Champions'), 1)                    AS avg_freq_score;
